const task = $('Start').item.json;
const systemPrompt = $('Read Extraction Prompt').item.json.data;
const pdfText = $('Read PDF').item.json.data || 'PDF binary - extract text content';

const payload = {
  model: 'kimi-k2-0711-preview',
  messages: [
    {
      role: 'system',
      content: systemPrompt
    },
    {
      role: 'user',
      content: `CONTEXT: subject=${task.subject}, grade=${task.grade}, lang=${task.lang}\n\nINPUT PDF CONTENT:\n${pdfText.substring(0, 50000)}\n\nTASK: Extract the FIRST THEME/CHAPTER only. Return JSON matching this schema exactly: ${JSON.stringify(require('fs').readFileSync('/home/node/nets/frameworks/schemas/lesson.json', 'utf8'))}`
    }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.3,
  max_tokens: 8000
};

return [{ json: { payload, task_id: task.task_id, lesson_id: task.lesson_id } }];

const response = $json;
const taskData = $('Compose Extraction Prompt').item.json;
const startTime = Date.now();

let lessonJson;
try {
  lessonJson = JSON.parse(response.choices[0].message.content);
} catch(e) {
  throw new Error('Invalid JSON from model: ' + e.message);
}

const schema = JSON.parse(require('fs').readFileSync('/home/node/nets/frameworks/schemas/lesson.json', 'utf8'));
const requiredFields = schema.required || [];
const missingFields = requiredFields.filter(f => !lessonJson[f]);
if (missingFields.length > 0) {
  throw new Error('Missing required fields: ' + missingFields.join(', '));
}

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;
const cacheHitPct = response.usage?.prompt_cache_hit_tokens ? (response.usage.prompt_cache_hit_tokens / tokensIn * 100) : 0;

const mdContent = JSON.stringify(lessonJson, null, 2);
const mdPath = `/home/node/nets/nets-output/${taskData.lesson_id}_lesson.json`;

return [{ json: {
  lesson_json: lessonJson,
  md_path: mdPath,
  md_content: mdContent,
  task_id: taskData.task_id,
  lesson_id: taskData.lesson_id,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd,
  cache_hit_pct: cacheHitPct,
  latency_ms: Date.now() - startTime
}}];
